// Triggered by daily schedule — run leveling for ALL active projects
const projects = $input.all().map(i => i.json)
    .filter(p => (p['Status'] || '').toLowerCase() === 'active' && p['Bid Tracker Sheet ID']);
return projects.map(p => ({ json: {
    found: true,
    projectName:       p['Project Name'] || '',
    bidTrackerSheetId: p['Bid Tracker Sheet ID'],
    tabName:           p['Tab Name'] || 'Sheet1',
    bidFolderId:       p['Bid Folder ID'] || '',
    simpleXlsxId:      p['Simple xlsx ID'] || '',
    btXlsxId:          p['BT xlsx ID'] || '',
    isSharedDrive:     (p['Is Shared Drive'] || '').toString().toUpperCase() === 'TRUE',
    runMode:           'scheduled-all',
}}));

// ─── PROJECT META (works in both schedule and webhook paths) ────────────────
const meta = (() => {
    try { const d = $('Split by Project').item.json; if (d && d.bidTrackerSheetId) return d; } catch(e) {}
    try { const d = $('Find Project & Tracker ID').first().json; if (d && d.bidTrackerSheetId) return d; } catch(e) {}
    return {};
})();
const webhookBody   = (() => { try { return $('Bid Leveling Webhook').first().json.body || {}; } catch(e) { return {}; } })();
const projectName   = meta.projectName || webhookBody.project_name || 'Unknown Project';
const bidTrackerSheetId = meta.bidTrackerSheetId || '';
const btXlsxId      = meta.btXlsxId || '';
const simpleXlsxId  = meta.simpleXlsxId || '';
const isSharedDrive = meta.isSharedDrive || false;
const tradeFilter   = (webhookBody.trade_filter || '').toLowerCase().trim();
const bids          = $input.all().map(i => i.json);
const dateStr       = new Date().toISOString().split('T')[0];
// ─── GROUP BIDS BY CSI DIVISION ──────────────────────────────────────────────
const tradeGroups = {};
for (const bid of bids) {
    const csi = (bid['CSI Division'] || bid['Division'] || '').toString().trim();
    const sub = (bid['Subcontractor'] || bid['Vendor'] || bid['Sub'] || '').toString().trim();
    if (!sub || sub === 'Subcontractor' || csi === csi.toLowerCase() && !csi) continue;

    const key = csi || 'Unknown';
    if (tradeFilter && !key.toLowerCase().includes(tradeFilter) && !sub.toLowerCase().includes(tradeFilter)) continue;

    if (!tradeGroups[key]) tradeGroups[key] = { division: key, bids: [] };

    const rawAmt = (bid['Bid Amount'] || '').toString().replace(/[$,\s]/g, '');
    const amount = parseFloat(rawAmt) || null;
    const note   = bid['Notes'] || bid['Notes (Claude)'] || bid['Notes/Issues'] || '';
    const contact = bid['Contact'] || bid['Contact #1'] || bid['Contact Name'] || '';
    const email   = bid['Email'] || bid['Email 1'] || '';
    const status  = bid['Status'] || '';

    tradeGroups[key].bids.push({ vendor: sub, amount, status, notes: note, contact, email,
        dateSent: bid['Date Sent'] || '', dateRcvd: bid['Date Received'] || '' });
}

// ─── LEVEL EACH TRADE GROUP ──────────────────────────────────────────────────
const leveled = [];
for (const [key, group] of Object.entries(tradeGroups).sort()) {
    const withAmt = group.bids.filter(b => b.amount !== null).sort((a, b) => a.amount - b.amount);
    const noAmt   = group.bids.filter(b => b.amount === null);
    const n = withAmt.length;

    let low = null, high = null, median = null, spread = null;
    if (n > 0) {
        low    = withAmt[0].amount;
        high   = withAmt[n - 1].amount;
        median = n % 2 === 0
            ? (withAmt[n/2-1].amount + withAmt[n/2].amount) / 2
            : withAmt[Math.floor(n/2)].amount;
        spread = n >= 2 ? ((high - low) / low * 100).toFixed(1) + '%' : 'N/A';
    }

    const fmt = v => v !== null ? '$' + v.toLocaleString('en-US', {minimumFractionDigits: 0}) : '—';
    const flag = b => {
        if (b.amount === null) {
            const st = b.status.toLowerCase();
            if (st.includes('decline') || st.includes('no bid')) return '✗ Declined';
            return '⏳ Pending';
        }
        if (median && b.amount > median * 1.25) return '⚠️ High';
        if (median && b.amount < median * 0.75) return '⚠️ Low';
        return '✓';
    };

    leveled.push({ key, division: group.division, bidCount: group.bids.length,
        received: n, pending: noAmt.length, low: fmt(low), high: fmt(high),
        median: fmt(median), spread,
        rows: [...withAmt.map(b => ({...b, flag: flag(b)})),
               ...noAmt.map(b => ({...b, flag: flag(b)}))] });
}

