const fmt2 = v => v !== null && v !== undefined ? '$' + Number(v).toLocaleString('en-US', {minimumFractionDigits: 0}) : '—';
let html = `<div style="font-family:Arial,sans-serif;font-size:13px;color:#1a1a1a;">
