for (const t of leveled) {
    html += `
<h3 style="color:#e05a00;border-bottom:1px solid #ddd;padding-bottom:4px;margin-top:24px;">${t.key}</h3>
<p style="font-size:11px;color:#555;margin:4px 0 8px;">
  Bids: ${t.bidCount} &nbsp;|&nbsp; Received: ${t.received} &nbsp;|&nbsp; Pending: ${t.pending}
  ${t.received > 0 ? ` &nbsp;|&nbsp; Low: ${t.low} &nbsp;|&nbsp; Median: ${t.median} &nbsp;|&nbsp; High: ${t.high} &nbsp;|&nbsp; Spread: ${t.spread}` : ''}
</p>
<table style="border-collapse:collapse;width:100%;margin-bottom:8px;font-size:12px;">
